/**
 * Shuffle an array using Fisher-Yates algorithm
 */
function shuffleArray(array) {
    const shuffled = [...array];
    for (let i = shuffled.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }
    return shuffled;
}

/**
 * Find the best matching subject key in the question bank
 */
function findSubjectKey(subject) {
    if (!subject) return null;

    const normalizedSubject = subject.toLowerCase().trim();

    // Direct match
    if (QUESTION_BANK[subject]) return subject;

    // Alias match
    if (SUBJECT_ALIASES[normalizedSubject]) {
        const aliasKey = SUBJECT_ALIASES[normalizedSubject];
        if (QUESTION_BANK[aliasKey]) return aliasKey;
    }

    // Case-insensitive match
    const keys = Object.keys(QUESTION_BANK);
    const exactMatch = keys.find(k => k.toLowerCase() === normalizedSubject);
    if (exactMatch) return exactMatch;

    // Partial match (subject contains or is contained in a key)
    const partialMatch = keys.find(k =>
        k.toLowerCase().includes(normalizedSubject) ||
        normalizedSubject.includes(k.toLowerCase())
    );
    if (partialMatch) return partialMatch;

    // Word overlap matching
    const subjectWords = normalizedSubject.split(/[\s&,]+/).filter(w => w.length > 2);
    let bestMatch = null;
    let bestScore = 0;

    for (const key of keys) {
        const keyWords = key.toLowerCase().split(/[\s&,]+/).filter(w => w.length > 2);
        const overlap = subjectWords.filter(w => keyWords.some(kw => kw.includes(w) || w.includes(kw))).length;
        if (overlap > bestScore) {
            bestScore = overlap;
            bestMatch = key;
        }
    }

    return bestScore > 0 ? bestMatch : null;
}

/**
 * Get fallback questions for a given subject, topic, difficulty, and count.
 * This is the main export used by quizService.js when AI generation fails.
 */
export function getFallbackQuestions(subject, topic, difficulty, numQuestions) {
    const subjectKey = findSubjectKey(subject);

    if (!subjectKey) {
        // Use a general knowledge fallback from available subjects
        const allQuestions = Object.values(QUESTION_BANK).flat();
        const shuffled = shuffleArray(allQuestions);
        return shuffled.slice(0, Math.min(numQuestions || 10, 30));
    }

    // Merge static bank with cached AI questions
    let questions = [...QUESTION_BANK[subjectKey]];
    try {
        const cached = JSON.parse(localStorage.getItem('aiQuestionCache') || '{}');
        const cachedForSubject = cached[subjectKey] || cached[subject] || [];
        if (cachedForSubject.length > 0) {
            const existingTexts = new Set(questions.map(q => q.question));
            const newQuestions = cachedForSubject.filter(q => !existingTexts.has(q.question));
            questions = [...questions, ...newQuestions];
        }
    } catch (e) { /* ignore cache errors */ }

    // --- Session-based deduplication: exclude previously shown questions ---
    let seenQuestions = [];
    try {
        seenQuestions = JSON.parse(sessionStorage.getItem('seenQuizQuestions') || '[]');
    } catch (e) { /* ignore */ }

    const unseenQuestions = questions.filter(q => !seenQuestions.includes(q.question));
    // Use unseen if enough, otherwise reset and use all
    if (unseenQuestions.length >= Math.min(numQuestions || 10, 5)) {
        questions = unseenQuestions;
    } else {
        // Reset seen questions for this subject — all have been shown
        seenQuestions = [];
    }

    // Filter by difficulty
    const normalizedDifficulty = (difficulty || 'Mixed').toLowerCase().trim();

    if (normalizedDifficulty === 'mixed' || normalizedDifficulty === 'all') {
        // Mixed: take roughly equal from each difficulty
        const easy = questions.filter(q => q.difficulty === 'Easy');
        const medium = questions.filter(q => q.difficulty === 'Medium');
        const hard = questions.filter(q => q.difficulty === 'Hard');

        const perDifficulty = Math.ceil((numQuestions || 10) / 3);
        questions = [
            ...shuffleArray(easy).slice(0, perDifficulty),
            ...shuffleArray(medium).slice(0, perDifficulty),
            ...shuffleArray(hard).slice(0, perDifficulty)
        ];
    } else {
        // Map difficulty aliases
        const difficultyMap = { 'easy': 'Easy', 'medium': 'Medium', 'mid': 'Medium', 'hard': 'Hard' };
        const targetDifficulty = difficultyMap[normalizedDifficulty] || 'Medium';

        const filtered = questions.filter(q => q.difficulty === targetDifficulty);

        // If not enough questions at target difficulty, supplement with others
        if (filtered.length >= (numQuestions || 10)) {
            questions = filtered;
        } else {
            // Use filtered + remaining from other difficulties
            const remaining = questions.filter(q => q.difficulty !== targetDifficulty);
            questions = [...filtered, ...shuffleArray(remaining)];
        }
    }

    // Filter by topic if provided and matches
    if (topic && topic !== 'General' && topic !== 'All Topics') {
        const topicLower = topic.toLowerCase();
        const topicFiltered = questions.filter(q =>
            q.topic && q.topic.toLowerCase().includes(topicLower)
        );
        if (topicFiltered.length >= Math.min(numQuestions || 10, 5)) {
            questions = topicFiltered;
        }
    }

    // Clamp numQuestions between 5 and 30
    const count = Math.max(5, Math.min(numQuestions || 10, 30));

    // Shuffle and return requested count
    const shuffled = shuffleArray(questions);
    const selected = shuffled.slice(0, Math.min(count, shuffled.length));

    // --- Track selected questions in sessionStorage ---
    try {
        const newSeen = [...seenQuestions, ...selected.map(q => q.question)];
        sessionStorage.setItem('seenQuizQuestions', JSON.stringify(newSeen));
    } catch (e) { /* ignore storage errors */ }

    // Final shuffle to interleave difficulties
    return shuffleArray(selected).map(q => ({
        ...q,
        options: q.options
    }));
}

export default QUESTION_BANK;

/**
 * Cache AI-generated questions into localStorage so they enrich the question bank.
 * Deduplicates by question text and caps at 200 per subject to limit storage.
 * @param {string} subject - The subject name
 * @param {Array} questions - Array of AI question objects
 */
export function cacheAiQuestions(subject, questions) {
    if (!subject || !questions || questions.length === 0) return;
    try {
        const cache = JSON.parse(localStorage.getItem('aiQuestionCache') || '{}');
        const existing = cache[subject] || [];
        const existingTexts = new Set(existing.map(q => q.question));
        const newQuestions = questions.filter(q =>
            q.question && !existingTexts.has(q.question)
        ).map(q => ({
            question: q.question,
            options: q.options,
            correctAnswer: q.correctAnswer,
            explanation: q.explanation || '',
            difficulty: q.difficulty || 'Medium',
            topic: q.topic || 'General'
        }));
        if (newQuestions.length > 0) {
            cache[subject] = [...existing, ...newQuestions].slice(-200);
            localStorage.setItem('aiQuestionCache', JSON.stringify(cache));
            console.log(`📚 Cached ${newQuestions.length} AI questions for ${subject} (total: ${cache[subject].length})`);
        }
    } catch (e) {
        console.warn('Failed to cache AI questions:', e.message);
    }
}
